definition.customCSS:
.[$FRAGMENT_CLASS$] h2 {
  margin-bottom: var(--spacer-4, 1.5rem) !important;
}

.[$FRAGMENT_CLASS$] h2::after{
border-bottom: 4px solid var(--primary, #0B5FFF);
  content: '';
  display: inline-block;
  margin: 0 0 0 0.3rem;
  width: 1.5rem;
}

.[$FRAGMENT_CLASS$] .portlet-document-library {
  background-color: #FFF;
  border: 1px solid rgba(0, 0, 0, 0.125);
  border-radius: 1.25rem;
  margin-bottom: 5rem;
  overflow: hidden;
}

.[$FRAGMENT_CLASS$] .portlet-document-library .container-view {
  padding-top: 0;
  padding-bottom: 0;
}

.[$FRAGMENT_CLASS$] .portlet-document-library .document-container {
  border: 1px solid transparent;
}

.[$FRAGMENT_CLASS$] .portlet-document-library .document-container .card-page {
  margin-bottom: 0;
  padding: 1rem;
}

.[$FRAGMENT_CLASS$] .portlet-document-library .document-library-breadcrumb {
  padding: 0 1rem;
  border-top: 1px solid rgba(0, 0, 0, 0.125);
  border-bottom: 1px solid rgba(0, 0, 0, 0.125);
}

.[$FRAGMENT_CLASS$] .portlet-document-library .card-section-header,
.[$FRAGMENT_CLASS$] .portlet-document-library .list-group-header {
  display: none;
}

.[$FRAGMENT_CLASS$] .portlet-document-library .card-page-item-asset {
  flex-basis: auto;
}

.[$FRAGMENT_CLASS$] .portlet-document-library .cke_bottom,
.[$FRAGMENT_CLASS$] .portlet-document-library .cke_top {
  display: none;
}

.[$FRAGMENT_CLASS$] .portlet-document-library .cke_contents {
  border: 0 !important;
}

.[$FRAGMENT_CLASS$] .portlet-document-library .form-check-card {
  margin-bottom: 1rem;
  min-width: 285px;
  max-width: 285px;
}

.[$FRAGMENT_CLASS$] .portlet-document-library .taglib-empty-result-message {
  margin-bottom: var(--spacer-4, 1.5rem);
}
